async fn insert_entries(
        store: &Arc<LiteStore>,
        scope: &str,
        count: usize,
    ) -> Vec<KnowledgeEntry> {
        let mut entries = Vec::new();
        for i in 0..count {
            let mut entry = KnowledgeEntry::new(
                format!("knowledge entry {i} about topic {}", i % 5),
                scope.to_string(),
                "v1".to_string(),
            );
            entry.embedding = Some(vec![1.0, i as f32 * 0.01, 0.0]);
            store.insert(&entry).await.unwrap();
            entries.push(entry);
        }
        entries
    }
